"use client";

import { useState } from "react";

interface SectionCardProps {
  sectionId: string;
  title: string;
  badge?: string;
  children: React.ReactNode;
  defaultOpen?: boolean;
}

export default function SectionCard({ sectionId, title, badge, children, defaultOpen = false }: SectionCardProps) {
  const [open, setOpen] = useState(defaultOpen);

  return (
    <div className="glass rounded-xl overflow-hidden transition-all duration-200">
      <button
        onClick={() => setOpen(!open)}
        className="w-full flex items-center justify-between px-4 py-3.5 hover:bg-white/5 transition-colors duration-150"
        aria-expanded={open}
      >
        <div className="flex items-center gap-2.5">
          <span className="text-xs font-semibold text-blue-400 bg-blue-500/10 px-2 py-0.5 rounded-md border border-blue-500/20">
            {sectionId}
          </span>
          <span className="text-sm font-semibold text-white">{title}</span>
          {badge && (
            <span className="text-xs text-slate-400 bg-slate-700/50 px-2 py-0.5 rounded-md">{badge}</span>
          )}
        </div>
        <svg
          className={`w-4 h-4 text-slate-400 transition-transform duration-200 ${open ? "rotate-180" : ""}`}
          fill="none"
          stroke="currentColor"
          viewBox="0 0 24 24"
        >
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
        </svg>
      </button>

      {open && (
        <div className="px-4 pb-4 pt-1 border-t border-white/5 fade-in">
          {children}
        </div>
      )}
    </div>
  );
}
